INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), '2co', 9, 1, NULL, 'Jonathan Edwards em 2Co 9:1', 'Jonathan Edwards interpreta este versículo a partir de a piedade prática e a santificação do coração. Em 2 Coríntios 9, Deus revela evangelho da graça e vida em santidade de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Jonathan Edwards', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '2co', 10, 1, NULL, 'Charles Hodge em 2Co 10:1', 'Charles Hodge destaca a coerência doutrinária aplicada à vida cristã. Em 2 Coríntios 10, o foco recai sobre evangelho da graça e vida em santidade e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Charles Hodge', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '2co', 11, 1, NULL, 'Agostinho de Hipona em 2Co 11:1', 'Na leitura de Agostinho de Hipona, vemos a leitura cristológica e eclesial da passagem. 2 Coríntios 11 evidencia evangelho da graça e vida em santidade como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Agostinho de Hipona', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), '2co', 12, 1, NULL, 'Theodore Beza em 2Co 12:1', 'Segundo Theodore Beza, a centralidade das Escrituras e da graça soberana ilumina o sentido deste texto. 2 Coríntios 12 mostra que evangelho da graça e vida em santidade sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Theodore Beza', 'commentary', '#800080', NOW()),
(gen_random_uuid(), '2co', 13, 1, NULL, 'R. A. Torrey em 2Co 13:1', 'Na leitura de R. A. Torrey, vemos o chamado ao arrependimento, fé viva e missão. 2 Coríntios 13 evidencia evangelho da graça e vida em santidade como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'R. A. Torrey', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'gl', 1, 1, NULL, 'Bernardo de Claraval em Gl 1:1', 'Segundo Bernardo de Claraval, a síntese entre fé, razão e vida santa ilumina o sentido deste texto. Gálatas 1 mostra que evangelho da graça e vida em santidade sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Bernardo de Claraval', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'gl', 2, 1, NULL, 'William Gurnall em Gl 2:1', 'Na leitura de William Gurnall, vemos a piedade prática e a santificação do coração. Gálatas 2 evidencia evangelho da graça e vida em santidade como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'William Gurnall', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'gl', 3, 1, NULL, 'Louis Berkhof em Gl 3:1', 'Segundo Louis Berkhof, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Gálatas 3 mostra que evangelho da graça e vida em santidade sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Louis Berkhof', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'gl', 4, 1, NULL, 'Anselmo de Cantuária em Gl 4:1', 'Anselmo de Cantuária destaca a síntese entre fé, razão e vida santa. Em Gálatas 4, o foco recai sobre evangelho da graça e vida em santidade e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Anselmo de Cantuária', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'gl', 5, 1, NULL, 'William Perkins em Gl 5:1', 'William Perkins interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Gálatas 5, Deus revela evangelho da graça e vida em santidade de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'William Perkins', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'gl', 6, 1, NULL, 'B. B. Warfield em Gl 6:1', 'B. B. Warfield destaca a coerência doutrinária aplicada à vida cristã. Em Gálatas 6, o foco recai sobre evangelho da graça e vida em santidade e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'B. B. Warfield', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'ef', 1, 1, NULL, 'F. B. Meyer em Ef 1:1', 'F. B. Meyer interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em Efésios 1, Deus revela evangelho da graça e vida em santidade de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'F. B. Meyer', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'ef', 2, 1, NULL, 'Gregório de Nissa em Ef 2:1', 'Segundo Gregório de Nissa, a leitura cristológica e eclesial da passagem ilumina o sentido deste texto. Efésios 2 mostra que evangelho da graça e vida em santidade sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Gregório de Nissa', 'commentary', '#8B4513', NOW()),
